using System.Text;
using System.Threading;

namespace ShaRPC.SourceGenerator;

/// <summary>
/// Generates client proxy classes for ShaRPC services. The generated proxy implements
/// the user's interface exactly — same return types, same parameter list, only adding
/// a forwarding body to <see cref="ShaRPC.Core.IRpcInvoker"/>. All emitted
/// type references are fully qualified with <c>global::</c> so the generated file
/// never depends on the user's <c>using</c> set.
/// </summary>
internal static class ProxyGenerator
{
    public static string Generate(
        ServiceModel service,
        EquatableArray<AsyncSiblingMethod> siblingMethods,
        CancellationToken ct = default)
    {
        var sb = new StringBuilder();
        var proxyName = NamingHelpers.StripInterfacePrefix(service.InterfaceName) + "Proxy";
        var qualifiedInterface = QualifyServiceType(service, service.InterfaceName);
        var qualifiedAsyncSibling = QualifyServiceType(
            service,
            NamingHelpers.AsyncSiblingInterfaceName(service.InterfaceName));

        // The proxy class implements both the user's interface and the generated async
        // sibling so callers can pick the blocking or non-blocking view.
        var baseList = siblingMethods.IsEmpty
            ? qualifiedInterface
            : $"{qualifiedInterface}, {qualifiedAsyncSibling}";

        sb.AppendLine("// <auto-generated />");
        sb.AppendLine("#nullable enable");
        sb.AppendLine();

        if (!string.IsNullOrEmpty(service.Namespace))
        {
            sb.AppendLine($"namespace {IdentifierHelpers.EscapeNamespace(service.Namespace)}");
            sb.AppendLine("{");
        }

        sb.AppendLine("    /// <summary>");
        sb.AppendLine($"    /// Client proxy for {service.InterfaceName}.");
        sb.AppendLine("    /// </summary>");
        sb.AppendLine($"    public sealed class {proxyName} : {baseList}");
        sb.AppendLine("    {");
        sb.AppendLine("        private readonly global::ShaRPC.Core.IRpcInvoker _invoker;");
        sb.AppendLine("        /// <summary>Non-null when this proxy targets a sub-service instance returned by a parent call.</summary>");
        sb.AppendLine("        private readonly string? _instanceId;");
        sb.AppendLine();
        sb.AppendLine($"        public {proxyName}(global::ShaRPC.Core.IRpcInvoker client)");
        sb.AppendLine("        {");
        sb.AppendLine("            this._invoker = client ?? throw new global::System.ArgumentNullException(nameof(client));");
        sb.AppendLine("            this._instanceId = null;");
        sb.AppendLine("        }");
        sb.AppendLine();
        sb.AppendLine($"        /// <summary>Constructs a proxy bound to a specific server-side instance.</summary>");
        sb.AppendLine($"        public {proxyName}(global::ShaRPC.Core.IRpcInvoker client, string instanceId)");
        sb.AppendLine("        {");
        sb.AppendLine("            this._invoker = client ?? throw new global::System.ArgumentNullException(nameof(client));");
        sb.AppendLine("            this._instanceId = instanceId ?? throw new global::System.ArgumentNullException(nameof(instanceId));");
        sb.AppendLine("        }");

        foreach (var method in service.Methods.Array)
        {
            ct.ThrowIfCancellationRequested();
            sb.AppendLine();
            GenerateProxyMethod(sb, service, method, proxyName, ct);
            if (ProxyGenerationHelpers.MethodNameRequiresExplicitImplementation(method.Name, proxyName))
            {
                foreach (var implementationType in method.AdditionalExplicitImplementationTypes.Array)
                {
                    ct.ThrowIfCancellationRequested();
                    sb.AppendLine();
                    GenerateProxyMethod(
                        sb,
                        service,
                        method with { ExplicitImplementationType = implementationType },
                        proxyName,
                        ct);
                }
            }
        }

        foreach (var s in siblingMethods.Array)
        {
            ct.ThrowIfCancellationRequested();
            if (!s.RequiresExtraProxyMethod &&
                !ProxyGenerationHelpers.MethodNameRequiresExplicitImplementation(s.Name, proxyName))
            {
                continue;
            }

            sb.AppendLine();
            GenerateAsyncSiblingMethod(sb, service, s, proxyName, qualifiedAsyncSibling, ct);
        }

        sb.AppendLine("    }");

        if (!string.IsNullOrEmpty(service.Namespace))
        {
            sb.AppendLine("}");
        }

        return sb.ToString();
    }
    private static string QualifyServiceType(ServiceModel service, string typeName) =>
        IdentifierHelpers.QualifyTypeName(service.Namespace, typeName);

    private static void GenerateProxyMethod(
        StringBuilder sb,
        ServiceModel service,
        MethodModel method,
        string proxyName,
        CancellationToken ct)
    {
        var paramList = new StringBuilder();
        ProxyGenerationHelpers.AppendParameterList(paramList, method.Parameters, ct);

        var declaredReturn = method.DeclaredReturnType;
        // Stubs stay non-async so out-parameters are definitely assigned by throw.
        var asyncKeyword = method.UnsupportedReason is null && RequiresAsyncStateMachine(method.ReturnKind)
            ? "async "
            : string.Empty;
        var unsafeKeyword = method.RequiresUnsafeSignature ? "unsafe " : string.Empty;
        var ctArg = ProxyGenerationHelpers.GetCancellationTokenArgument(method.Parameters, ct);
        var explicitInterface = ProxyGenerationHelpers.MethodNameRequiresExplicitImplementation(method.Name, proxyName);
        var access = explicitInterface ? string.Empty : "public ";
        var target = explicitInterface ? method.ExplicitImplementationType + "." + method.Name : method.Name;

        sb.AppendLine($"        {access}{unsafeKeyword}{asyncKeyword}{method.ReturnRefKindKeyword}{declaredReturn} {target}{method.TypeParameterList}({paramList}){method.ConstraintClauses}");
        sb.AppendLine("        {");

        if (method.UnsupportedReason is not null)
        {
            sb.AppendLine($"            throw new global::System.NotSupportedException(\"ShaRPC cannot marshal '{IdentifierHelpers.UnescapeIdentifier(method.Name)}': {LiteralHelpers.EscapeStringLiteral(method.UnsupportedReason)}\");");
        }
        else
        {
            var locals = new GeneratedLocalNames(method.Parameters, ct);
            if (method.ReturnKind == MethodReturnKind.AsyncEnumerable &&
                HasStreamedRequestParameter(method, ct))
            {
                EmitLazyAsyncEnumerableInvocation(sb, service, method, ctArg, locals, ct);
            }
            else
            {
                var invocation = BuildClientInvocation(sb, service, method, ctArg, locals, ct);
                ProxyInvocationCleanupEmitter.EmitProxyInvocation(
                    sb,
                    method,
                    invocation.Invocation,
                    invocation.Reservations,
                    locals,
                    ct);
            }
        }

        sb.AppendLine("        }");
    }

    private static bool HasStreamedRequestParameter(MethodModel method, CancellationToken ct)
    {
        foreach (var parameter in method.Parameters.Array)
        {
            ct.ThrowIfCancellationRequested();
            if (parameter.StreamKind != ParameterStreamKind.None)
            {
                return true;
            }
        }

        return false;
    }

    private static void EmitLazyAsyncEnumerableInvocation(
        StringBuilder sb,
        ServiceModel service,
        MethodModel method,
        string ctArg,
        GeneratedLocalNames locals,
        CancellationToken ct)
    {
        var iteratorName = locals.Reserve("__sharpc_enumerate", ct);
        var enumerationCt = locals.Reserve("__sharpc_enumerationCt", ct);
        var sequenceName = locals.Reserve("__sharpc_sequence", ct);
        var enumeratorName = locals.Reserve("__sharpc_enumerator", ct);
        sb.AppendLine($"            return {iteratorName}();");
        sb.AppendLine();
        sb.AppendLine($"            async {method.DeclaredReturnType} {iteratorName}([global::System.Runtime.CompilerServices.EnumeratorCancellation] global::System.Threading.CancellationToken {enumerationCt} = default)");
        sb.AppendLine("            {");
        var invocation = BuildClientInvocation(
            sb,
            service,
            method,
            ctArg,
            locals,
            ct,
            "                ");
        ProxyInvocationCleanupEmitter.EmitInvocationAssignment(
            sb,
            method.DeclaredReturnType,
            sequenceName,
            invocation.Invocation,
            invocation.Reservations,
            locals,
            ct,
            "                ");
        sb.AppendLine($"                var {enumeratorName} = {sequenceName}.GetAsyncEnumerator({enumerationCt});");
        sb.AppendLine("                try");
        sb.AppendLine("                {");
        sb.AppendLine($"                    while (await {enumeratorName}.MoveNextAsync())");
        sb.AppendLine("                    {");
        sb.AppendLine($"                        yield return {enumeratorName}.Current;");
        sb.AppendLine("                    }");
        sb.AppendLine("                }");
        sb.AppendLine("                finally");
        sb.AppendLine("                {");
        sb.AppendLine($"                    await {enumeratorName}.DisposeAsync();");
        sb.AppendLine("                }");
        sb.AppendLine("            }");
    }

    /// <summary>
    /// Builds the call to <c>_invoker.InvokeAsync</c> or <c>_invoker.InvokeOnInstanceAsync</c>.
    /// For sub-service-returning methods, the wire response type is always
    /// <c>ServiceHandle</c>; the caller wraps it in a generated sub-proxy. The emitted
    /// expression branches on <c>_instanceId</c> so the same proxy class can serve both
    /// the top-level and the nested-instance call paths.
    /// </summary>
    private static (string Invocation, System.Collections.Generic.List<(string HandleName, string ReservedName)>? Reservations) BuildClientInvocation(
        StringBuilder sb,
        ServiceModel service,
        MethodModel method,
        string ctArg,
        GeneratedLocalNames locals,
        CancellationToken ct,
        string indent = "            ")
    {
        var isSubServiceReturn = NamingHelpers.IsSubServiceReturn(method.ReturnKind);
        var hasReturn = NamingHelpers.HasReturnValue(method.ReturnKind);
        var returnType = isSubServiceReturn
            ? GetServiceHandleType(method)
            : method.UnwrappedReturnType is null
                ? null
                : ProxyGenerationHelpers.GetWireType(method.UnwrappedReturnType);
        var requestParameters = ProxyGenerationHelpers.GetRequestParameters(method.Parameters, ct);
        var streamSetup = ProxyStreamSetupEmitter.Emit(sb, method, requestParameters, locals, ct, indent);
        var streamArray = streamSetup.ArrayName;
        var useStreamAwareTaskValueInvocation =
            method.ReturnKind == MethodReturnKind.ValueTaskOf && streamArray is not null;
        var svc = service.ServiceName;
        var rpc = method.RpcName;
        var singletonMethod = GetInvokerMethod(
            method.ReturnKind,
            isInstanceScoped: false,
            useStreamAwareTaskValueInvocation);
        var instanceMethod = GetInvokerMethod(
            method.ReturnKind,
            isInstanceScoped: true,
            useStreamAwareTaskValueInvocation);

        // Build the type-parameter list and argument list once; switch between the two
        // overload prefixes via the ternary.
        string typeArgs;
        string callArgs;        // arguments after (service, method) for the singleton overload
        string callArgsInst;    // arguments after (service, instanceId, method) for instance

        if (requestParameters.Count == 0)
        {
            typeArgs = BuildTypeArgs(method.ReturnKind, requestType: null, returnType, hasReturn);
            callArgs = $"\"{svc}\", \"{rpc}\", {ctArg}";
            callArgsInst = $"\"{svc}\", this._instanceId!, \"{rpc}\", {ctArg}";
        }
        else if (requestParameters.Count == 1)
        {
            var p = requestParameters[0];
            var wireType = ProxyGenerationHelpers.GetWireType(p);
            var wireArgument = GetWireArgument(p, requestIndex: 0, streamSetup.Handles);
            typeArgs = BuildTypeArgs(method.ReturnKind, wireType, returnType, hasReturn);
            var streamArg = NeedsStreamArrayArgument(method.ReturnKind, streamArray)
                ? $", {streamArray ?? "null"}"
                : string.Empty;
            callArgs = $"\"{svc}\", \"{rpc}\", {wireArgument}{streamArg}, {ctArg}";
            callArgsInst = $"\"{svc}\", this._instanceId!, \"{rpc}\", {wireArgument}{streamArg}, {ctArg}";
        }
        else
        {
            var tupleTypes = new StringBuilder();
            var tupleValues = new StringBuilder();
            for (var i = 0; i < requestParameters.Count; i++)
            {
                ct.ThrowIfCancellationRequested();

                if (i > 0)
                {
                    tupleTypes.Append(", ");
                    tupleValues.Append(", ");
                }
                tupleTypes.Append(ProxyGenerationHelpers.GetWireType(requestParameters[i]));
                tupleValues.Append(GetWireArgument(requestParameters[i], i, streamSetup.Handles));
            }

            typeArgs = BuildTypeArgs(method.ReturnKind, $"({tupleTypes})", returnType, hasReturn);
            var streamArg = NeedsStreamArrayArgument(method.ReturnKind, streamArray)
                ? $", {streamArray ?? "null"}"
                : string.Empty;
            callArgs = $"\"{svc}\", \"{rpc}\", ({tupleValues}){streamArg}, {ctArg}";
            callArgsInst = $"\"{svc}\", this._instanceId!, \"{rpc}\", ({tupleValues}){streamArg}, {ctArg}";
        }

        var invocation =
            $"(this._instanceId is null ? this._invoker.{singletonMethod}{typeArgs}({callArgs}) : this._invoker.{instanceMethod}{typeArgs}({callArgsInst}))";
        if (useStreamAwareTaskValueInvocation)
        {
            invocation = $"new global::System.Threading.Tasks.ValueTask<{returnType}>({invocation})";
        }

        return (invocation, streamSetup.Reservations);
    }

    private static string GetServiceHandleType(MethodModel method) =>
        method.SubService?.AllowsNull == true
            ? "global::ShaRPC.Core.Protocol.ServiceHandle?"
            : "global::ShaRPC.Core.Protocol.ServiceHandle";

    private static string BuildTypeArgs(
        MethodReturnKind returnKind,
        string? requestType,
        string? returnType,
        bool hasReturn)
    {
        if (NamingHelpers.IsAsyncEnumerableReturn(returnKind))
        {
            return requestType is null
                ? $"<{returnType}>"
                : $"<{requestType}, {returnType}>";
        }

        if (NamingHelpers.IsStreamReturn(returnKind) || NamingHelpers.IsPipeReturn(returnKind))
        {
            return requestType is null ? string.Empty : $"<{requestType}>";
        }

        if (requestType is null)
        {
            return hasReturn ? $"<{returnType}>" : string.Empty;
        }

        return hasReturn ? $"<{requestType}, {returnType}>" : $"<{requestType}>";
    }

    private static bool NeedsStreamArrayArgument(MethodReturnKind returnKind, string? streamArray) =>
        streamArray is not null ||
        NamingHelpers.IsStreamReturn(returnKind) ||
        NamingHelpers.IsPipeReturn(returnKind) ||
        NamingHelpers.IsAsyncEnumerableReturn(returnKind);

    private static string GetWireArgument(
        ParameterModel parameter,
        int requestIndex,
        System.Collections.Generic.Dictionary<int, string> streamHandles) =>
        parameter.StreamKind == ParameterStreamKind.None
            ? ProxyGenerationHelpers.GetWireArgument(parameter)
            : streamHandles[requestIndex];

    private static string GetInvokerMethod(
        MethodReturnKind returnKind,
        bool isInstanceScoped,
        bool useStreamAwareTaskValueInvocation = false)
    {
        if (NamingHelpers.IsStreamReturn(returnKind))
        {
            return isInstanceScoped ? "InvokeStreamOnInstanceAsync" : "InvokeStreamAsync";
        }

        if (NamingHelpers.IsPipeReturn(returnKind))
        {
            return isInstanceScoped ? "InvokePipeOnInstanceAsync" : "InvokePipeAsync";
        }

        if (NamingHelpers.IsAsyncEnumerableReturn(returnKind))
        {
            var eager = returnKind == MethodReturnKind.TaskOfAsyncEnumerable ||
                returnKind == MethodReturnKind.ValueTaskOfAsyncEnumerable;
            return isInstanceScoped
                ? eager ? "InvokeAsyncEnumerableOnInstanceAsync" : "InvokeAsyncEnumerableOnInstance"
                : eager ? "InvokeAsyncEnumerableAsync" : "InvokeAsyncEnumerable";
        }

        if (returnKind == MethodReturnKind.ValueTaskOf && !useStreamAwareTaskValueInvocation)
        {
            return isInstanceScoped ? "InvokeValueOnInstanceAsync" : "InvokeValueAsync";
        }

        return isInstanceScoped ? "InvokeOnInstanceAsync" : "InvokeAsync";
    }

    /// <summary>
    /// Emits a non-blocking proxy method that satisfies the async sibling interface.
    /// Reuses the underlying RPC call site of the original method (same service, same
    /// wire method name) but returns a Task / Task&lt;T&gt; so the caller never blocks.
    /// </summary>
    private static void GenerateAsyncSiblingMethod(
        StringBuilder sb,
        ServiceModel service,
        AsyncSiblingMethod s,
        string proxyName,
        string qualifiedAsyncSibling,
        CancellationToken ct)
    {
        var paramList = new StringBuilder();
        ProxyGenerationHelpers.AppendParameterList(paramList, s.Parameters, ct);

        var declaredReturn = NamingHelpers.GetDeclaredReturnTypeText(
            s.SiblingReturnKind, s.Source.UnwrappedReturnType);
        var explicitInterface = ProxyGenerationHelpers.MethodNameRequiresExplicitImplementation(s.Name, proxyName);
        var access = explicitInterface ? string.Empty : "public ";
        var target = explicitInterface ? qualifiedAsyncSibling + "." + s.Name : s.Name;

        var asyncKeyword = RequiresAsyncStateMachine(s.SiblingReturnKind) ? "async " : string.Empty;
        sb.AppendLine($"        {access}{asyncKeyword}{declaredReturn} {target}({paramList})");
        sb.AppendLine("        {");

        // For the wire call, treat the sibling as having a CancellationToken AND the
        // sibling's return kind (so the invocation picks the right overload).
        var virtualSource = s.Source with
        {
            HasCancellationToken = true,
            ReturnKind = s.SiblingReturnKind,
            Parameters = s.Parameters,
        };
        var locals = new GeneratedLocalNames(s.Parameters, ct);
        var ctArg = ProxyGenerationHelpers.GetCancellationTokenArgument(s.Parameters, ct);
        if (virtualSource.ReturnKind == MethodReturnKind.AsyncEnumerable &&
            HasStreamedRequestParameter(virtualSource, ct))
        {
            EmitLazyAsyncEnumerableInvocation(sb, service, virtualSource, ctArg, locals, ct);
        }
        else
        {
            var invocation = BuildClientInvocation(sb, service, virtualSource, ctArg, locals, ct);
            ProxyInvocationCleanupEmitter.EmitProxyInvocation(
                sb,
                virtualSource,
                invocation.Invocation,
                invocation.Reservations,
                locals,
                ct);
        }

        sb.AppendLine("        }");
    }

    private static bool RequiresAsyncStateMachine(MethodReturnKind returnKind) =>
        returnKind is MethodReturnKind.TaskOfSubService or MethodReturnKind.ValueTaskOfSubService;
}
